import{_ as e,k as s,x as a,al as r}from"./chunks/framework.86H0f4-O.js";const i="/assets/4d4e2a18759e7121f14680394aacd260.DT6qT36h.jpg",o="/assets/screenshot_2026-03-12_16-03-57.C5c-ZasO.png",l="/assets/screenshot_2026-03-12_16-05-58.D_mLbLm9.png",p="/assets/screenshot_2026-03-12_16-06-15.C1pW1m4N.png",n="/assets/screenshot_2026-03-12_16-06-32.BDAD4rPq.png",h="/assets/screenshot_2026-03-12_16-06-54.BGLJaOBH.png",c="/assets/screenshot_2026-03-12_16-17-36.DSTTo1H8.png",m="/assets/screenshot_2026-03-12_16-19-15.DLkbg7s-.png",f=JSON.parse('{"title":"如何编辑Termux文件","description":"","frontmatter":{},"headers":[],"relativePath":"scripts/koimuxTUI/termux-edit-files.md","filePath":"scripts/koimuxTUI/termux-edit-files.md","lastUpdated":1773304080000}'),u={name:"scripts/koimuxTUI/termux-edit-files.md"};function d(g,t,x,_,k,b){return s(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="如何编辑termux文件" tabindex="-1">如何编辑Termux文件 <a class="header-anchor" href="#如何编辑termux文件" aria-label="Permalink to &quot;如何编辑Termux文件&quot;">​</a></h1><h2 id="一、准备工作-必做" tabindex="-1">一、准备工作（必做） <a class="header-anchor" href="#一、准备工作-必做" aria-label="Permalink to &quot;一、准备工作（必做）&quot;">​</a></h2><h3 id="_1-安装应用" tabindex="-1">1. 安装应用 <a class="header-anchor" href="#_1-安装应用" aria-label="Permalink to &quot;1. 安装应用&quot;">​</a></h3><ul><li>安装 <strong>MT管理器</strong> → <a href="https://mt2.cn/download" target="_blank" rel="noreferrer">https://mt2.cn/download</a></li></ul><h3 id="_2-termux-权限与配置-关键" tabindex="-1">2. Termux 权限与配置（关键） <a class="header-anchor" href="#_2-termux-权限与配置-关键" aria-label="Permalink to &quot;2. Termux 权限与配置（关键）&quot;">​</a></h3><p>为了授予外部存储权限，需要打开 Termux，执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">termux-setup-storage</span></span></code></pre></div><ul><li><p>如果提示确认 → 键入 <code>y</code> 并回车 以允许</p></li><li><p>如果弹出权限弹窗 → 允许</p></li></ul><p><img src="'+i+'" alt="alt text"></p><hr><p>允许外部应用访问</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#56B6C2;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> &quot;allow-external-apps = true&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#ABB2BF;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> ~/.termux/termux.properties</span></span></code></pre></div><hr><p>重启termux</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#56B6C2;">exit</span></span></code></pre></div><p>这会关闭termux，现在你需要重新打开termux。</p><p><strong>重要</strong>：后续操作时，<strong>Termux必须在后台运行，否则访问不了文件</strong>。</p><h2 id="二、mt管理器挂载-termux-目录" tabindex="-1">二、MT管理器挂载 Termux 目录 <a class="header-anchor" href="#二、mt管理器挂载-termux-目录" aria-label="Permalink to &quot;二、MT管理器挂载 Termux 目录&quot;">​</a></h2><ol><li>打开 <strong>MT管理器</strong></li><li>点击右上角 <strong>⋮（三个点）</strong> → <strong>添加本地存储</strong></li><li>在弹出的文件选择器里，点右上角 <strong>菜单</strong> → 选择 <strong>Termux</strong></li><li>确认后，MT左侧/右侧会出现 <strong>Termux</strong> 入口</li><li>进入即可看到 Termux 的 <strong>$HOME</strong> 目录（<code>~/</code>），直接编辑文件</li></ol><p>具体步骤请参考下方图解步骤：</p><p>图一：</p><p><img src="'+o+'" alt="alt text"></p><p>图二：</p><p><img src="'+l+'" alt="alt text"></p><p>图三：</p><p><img src="'+p+'" alt="alt text"></p><p>图四：</p><p><img src="'+n+'" alt="alt text"></p><p>图五：</p><p><img src="'+h+'" alt="alt text"></p><hr><h2 id="三、编辑示例" tabindex="-1">三、编辑示例 <a class="header-anchor" href="#三、编辑示例" aria-label="Permalink to &quot;三、编辑示例&quot;">​</a></h2><p>以下是编辑文件的示例方法，教程这里就以<code>chatluna</code>插件上传预设文件为示例。</p><p>按照上面图解步骤，你默认就能在找到 Termux 的 <strong>$HOME</strong> 目录找到名为koishi的文件夹，进入之后会看到各个koishi实例的名称。</p><p>点击进入你需要修改文件的实例里，就算是“进入了koishi的项目目录”</p><hr><p><img src="'+c+'" alt="alt text"></p><p>按照图示路径，在“koishi项目目录”下依次点击进入：</p><p>data → chathub → presets → 你需要编辑的预设文件</p><p>然后你就会看到这样的内容：</p><p>开始编辑吧~~~</p><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>YAML、YML文件有严格的缩进要求，</p><p>请你<strong>严格注意文件中的换行、空格、缩进</strong>，严格注意文件格式！</p><p>否则会导致预设格式错误而无法解析！</p></div><p><img src="'+m+'" alt="alt text"></p><p>另外，根据 chatluna预设文档，你可以在预设里使用很多变量，详情请参考 -&gt; <a href="https://chatluna.chat/development/call-core-services/preset.html#%E9%A2%84%E8%AE%BE%E6%A8%A1%E6%9D%BF%E5%8F%98%E9%87%8F" target="_blank" rel="noreferrer">https://chatluna.chat/development/call-core-services/preset.html#预设模板变量</a></p><hr><h2 id="四、常见问题与解决" tabindex="-1">四、常见问题与解决 <a class="header-anchor" href="#四、常见问题与解决" aria-label="Permalink to &quot;四、常见问题与解决&quot;">​</a></h2><h3 id="❌-mt看不到termux目录" tabindex="-1">❌ MT看不到Termux目录 <a class="header-anchor" href="#❌-mt看不到termux目录" aria-label="Permalink to &quot;❌ MT看不到Termux目录&quot;">​</a></h3><ul><li>确保 <strong>Termux在后台运行</strong></li><li>重新执行：<code>echo &quot;allow-external-apps = true&quot; &gt;&gt; ~/.termux/termux.properties</code> 并重启</li><li>安卓12+：设置 → 应用 → Termux → 权限 → 开启 <strong>所有文件访问</strong></li></ul><h3 id="❌-termux访问mt编辑的文件乱码" tabindex="-1">❌ Termux访问MT编辑的文件乱码 <a class="header-anchor" href="#❌-termux访问mt编辑的文件乱码" aria-label="Permalink to &quot;❌ Termux访问MT编辑的文件乱码&quot;">​</a></h3><ul><li>MT编辑时：右上角 <strong>⋮</strong> → <strong>编码</strong> → 选择 <strong>UTF-8</strong></li></ul>',50)])])}const q=e(u,[["render",d]]);export{f as __pageData,q as default};
